mapper.select:
SELECT stu.name AS studentName, s.name AS teacherName, l.title AS lessonName, t.score1 AS score1, t.score2 AS score2, t.score3 AS score3, t.score4 AS score4, t.content AS content, t.add_time AS addTime, t.anonymity AS anonymity FROM teach_evaluation t LEFT JOIN lesson l ON t.lesson_id = l.id LEFT JOIN staff s ON t.teacher_id = s.id LEFT JOIN student stu ON t.student_id = stu.id
AND t.lesson_id = #{lessonId}
AND t.teacher_id = #{teacherId}
AND t.student_id = #{studentId}
AND DATE(t.add_time) >= #{startTime}
AND DATE(t.add_time) <= #{endTime}
ORDER BY t.add_time DESC
